export function FinancialAuthority() {
  const { t } = useTranslation('organizationApplication');
  const { user } = useAuthStore();
  const { currentAccount } = useGetAccount();

  const handlePlaidIdvSuccess = useCallback(() => {
    console.log('handlePlaidIdvSuccess');
  }, []);

  const { data: accounts } = useGetAccounts({
    page: 1,
    perPage: 1,
    status: 'active',
    userId: currentAccount?.id,
  });

  const activeAccount = accounts?.[0];

  const { showToast } = useToast();
  const { navigateNextStep } = useSteps();
  const { createInviteAsync, isCreatingInvite } = useCreateInvite({ showToasts: false });

  const [isChangingOwner, { off: useCurrentOwner, on: changeOwner }] = useBoolean();
  const [isFinancialAuthority, { toggle: toggleFinancialAuthority }] = useBoolean();

  const { isLoading: isUpdatingAccount, updateAccountAsync } = useUpdateAccount({
    shouldShowErrorToast: true,
    shouldShowToast: false,
  });
  const { isLoading: isUpdatingUserDetails, updateUserDetailsAsync } = useUpdateUser({
    shouldShowErrorToast: true,
    shouldShowToast: false,
    userId: user?.id,
  });

  const isAccepting = isUpdatingAccount || isUpdatingUserDetails;
  const isAlreadySigned = !!currentAccount?.signature?.url;
  const showSignedAlready = !isChangingOwner && !!isAlreadySigned && !isAccepting;

  const accept = async ({ account, user: userDetails }: AcceptParams) => {
    await updateUserDetailsAsync(userDetails);
    await updateAccountAsync({ updates: account });
    navigateNextStep();
  };

  const { superAdminListId } = usePermissionListOptions();

  if (!superAdminListId) {
    return <Loading />;
  }

  const inviteOwner = ({ email }: { email: string }) => {
    createInviteAsync(
      { accessLevel: AccessLevel.SuperAdmin, email, permissionListId: superAdminListId },
      {
        onError: () =>
          showToast({
            message: t('financialAuthority.requests.onInvitationError'),
            variant: 'error',
          }),
        onSuccess: () => navigateNextStep(),
      }
    );
  };

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('financialAuthority.heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Flex direction="column" gap={6}>
        <Panel p={6} variant="primary">
          <Flex direction="column" gap={6}>
            <Paragraph>
              <Trans
                components={[<strong key="intro-strong" />]}
                i18nKey="financialAuthority.intro"
                t={t}
              />
            </Paragraph>
            <UnorderedList color="neutral.600">
              <ListItem>
                <Paragraph>{t('financialAuthority.requirements.listedOnPublicRecord')}</Paragraph>
              </ListItem>
              <ListItem>
                <Paragraph>{t('financialAuthority.requirements.legalAbility')}</Paragraph>
              </ListItem>
            </UnorderedList>

            {showSignedAlready ? (
              <>
                <Flex gap={2}>
                  <CheckmarkCircleIcon color="green.500" h="15px" w="15px" />
                  <Label variant="medium">
                    {t('financialAuthority.alreadySigned.ownerConfirmed', {
                      fullOwnerName: `${currentAccount?.signatory?.firstName} ${currentAccount?.signatory?.lastName}`,
                    })}
                  </Label>
                </Flex>
                <Paragraph>
                  <Trans
                    components={[
                      <Button
                        key="change-owner-button"
                        onClick={changeOwner}
                        textDecoration="none"
                        variant="link"
                      />,
                    ]}
                    i18nKey="financialAuthority.alreadySigned.changeOwner"
                    t={t}
                  />
                </Paragraph>
              </>
            ) : (
              <>
                <RadioGroup
                  formControlProps={{ marginBottom: 0 }}
                  label={t('financialAuthority.acceptanceRadio.title')}
                  name="isFinancialAuthority"
                  onChange={toggleFinancialAuthority}
                  value={isFinancialAuthority}
                >
                  <Stack spacing={4}>
                    <RadioControl key="yes" value="true">
                      <Label variant="bold">{t('financialAuthority.acceptanceRadio.yes')}</Label>
                      <Meta>{t('financialAuthority.acceptanceRadio.yesHelper')}</Meta>
                    </RadioControl>
                    <RadioControl key="no" value="false">
                      <Label variant="bold">{t('financialAuthority.acceptanceRadio.no')}</Label>
                      <Meta>{t('financialAuthority.acceptanceRadio.noHelper')}</Meta>
